import{_ as i,o as a,c as t,a2 as o}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"RFC-0010: Raspberry Pi Image Deployment","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/rfcs/0010-raspberry-pi-image-deployment.md","filePath":"sovereign-os/rfcs/0010-raspberry-pi-image-deployment.md"}'),r={name:"sovereign-os/rfcs/0010-raspberry-pi-image-deployment.md"};function n(s,e,l,d,c,p){return a(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="rfc-0010-raspberry-pi-image-deployment" tabindex="-1">RFC-0010: Raspberry Pi Image Deployment <a class="header-anchor" href="#rfc-0010-raspberry-pi-image-deployment" aria-label="Permalink to &quot;RFC-0010: Raspberry Pi Image Deployment&quot;">​</a></h1><p><strong>Status:</strong> Proposed<br><strong>Author:</strong> Project creator and Codex<br><strong>Created:</strong> 2026-07-19<br><strong>Target phase:</strong> Phase 01<br><strong>Related decision:</strong> <a href="./../adrs/0001-phase-01-appliance-architecture.html">ADR-0001</a></p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Build a reproducible Raspberry Pi OS Lite 64-bit disk image that embeds a pinned official Pi-hole ARM64 container. On first boot, an idempotent systemd unit creates device identity and secrets, imports the container, starts DNS, configures <code>/dns/*</code> reverse-proxy routing, and advertises <code>sovereign.local</code> over mDNS.</p><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>The project needs a first artifact that proves Sovereign can deliver self-hosted software as a coherent appliance rather than a collection of manual installation steps.</p><p>The solution must:</p><ul><li>be writable using Raspberry Pi Imager;</li><li>boot without user shell work;</li><li>avoid build-machine identity and minimize the lifetime of preview bootstrap credentials;</li><li>operate without downloading Pi-hole on first boot;</li><li>persist configuration across reboot and container replacement;</li><li>reserve root <code>/admin</code> and <code>/api</code> paths for future Sovereign services;</li><li>remain reproducible and auditable.</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>One compressed flashable image for Raspberry Pi 5.</li><li>Raspberry Pi OS Lite 64-bit base.</li><li>Pi-hole v6 deployed using the official ARM64 container.</li><li>Immutable container digest and recorded provenance.</li><li>Offline first boot after the image has been downloaded.</li><li>Unique first-boot identity and Pi-hole credential.</li><li>Pi-hole DNS on TCP/UDP 53.</li><li>Pi-hole UI and API under <code>/dns/*</code>.</li><li><code>sovereign.local</code> mDNS discovery with direct-IP fallback.</li><li>Persistent Pi-hole data and recoverable initialization.</li></ul><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h2><ul><li>Sovereign dashboard or API</li><li>AI or LLM runtime</li><li>Public remote access</li><li>Automatic router configuration</li><li>Pi-hole DHCP by default</li><li>Multi-device clustering</li><li>Multi-platform images</li><li>General container marketplace</li><li>Fully automatic updates or transactional rollback</li></ul><h2 id="proposed-build-inputs" tabindex="-1">Proposed Build Inputs <a class="header-anchor" href="#proposed-build-inputs" aria-label="Permalink to &quot;Proposed Build Inputs&quot;">​</a></h2><p>Every release build must pin and record:</p><ul><li>source repository revision;</li><li>image-build-tool revision;</li><li>Raspberry Pi OS release and base inputs;</li><li>Debian package snapshot or resolved package versions where practical;</li><li>Docker Engine and Compose versions;</li><li>Pi-hole container repository, version, platform, and digest;</li><li>Nginx and Avahi package versions;</li><li>build environment and architecture;</li><li>release configuration and build timestamp.</li></ul><p>Mutable references such as <code>latest</code> must not be release inputs.</p><h2 id="image-build" tabindex="-1">Image Build <a class="header-anchor" href="#image-build" aria-label="Permalink to &quot;Image Build&quot;">​</a></h2><p>The build will:</p><ol><li>Generate a Raspberry Pi OS Lite 64-bit root filesystem and boot partition.</li><li>Install Docker Engine, Compose support, Nginx, Avahi, and required utilities.</li><li>Add Sovereign-owned systemd units and configuration.</li><li>Pull the exact Linux ARM64 Pi-hole container by digest in the build environment.</li><li>Export it as an OCI or Docker archive.</li><li>Store the archive and digest manifest under <code>/opt/sovereign/bootstrap/</code>.</li><li>Add an idempotent first-boot initializer.</li><li>Remove package caches, temporary files, build SSH keys, machine identity, and logs.</li><li>Export the raw image.</li><li>Verify partitions and filesystem integrity.</li><li>Compress, checksum, and produce release metadata.</li></ol><p>The <a href="./../research/image-build-system-assessment.html">image-build assessment</a> recommends <code>rpi-image-gen</code>, pinned to an exact release tag and commit, using a supported native ARM64 Debian/Raspberry Pi OS build host. This becomes the proposed builder when the minimal boot, Sovereign layer, and persistent-partition proof builds pass. <code>pi-gen</code> remains the fallback if a blocking <code>rpi-image-gen</code> defect cannot be resolved within the POC scope.</p><h2 id="runtime-components" tabindex="-1">Runtime Components <a class="header-anchor" href="#runtime-components" aria-label="Permalink to &quot;Runtime Components&quot;">​</a></h2><h3 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to &quot;Docker&quot;">​</a></h3><p>Docker is an internal deployment mechanism. Users do not need to run Compose commands for normal use.</p><p>The service definition must:</p><ul><li>pin Pi-hole by digest;</li><li>publish DNS on TCP and UDP 53;</li><li>publish Pi-hole HTTP only on a loopback host port;</li><li>mount persistent <code>/etc/pihole</code> data;</li><li>use a read-only secret file for the administrator password;</li><li>define bounded logs and restart behavior;</li><li>avoid privileges and Linux capabilities not required for DNS-only operation;</li><li>leave DHCP and NTP ports unpublished.</li></ul><h3 id="nginx" tabindex="-1">Nginx <a class="header-anchor" href="#nginx" aria-label="Permalink to &quot;Nginx&quot;">​</a></h3><p>Nginx owns LAN TCP port 80 and routes only <code>/dns/*</code> to Pi-hole. It strips <code>/dns</code> before proxying. Pi-hole is configured with <code>webserver.paths.prefix = &quot;/dns&quot;</code> so its generated links, redirects, and API calls retain the external prefix.</p><p>Nginx must normalize or reject ambiguous paths and prevent traversal or prefix escape.</p><h3 id="avahi" tabindex="-1">Avahi <a class="header-anchor" href="#avahi" aria-label="Permalink to &quot;Avahi&quot;">​</a></h3><p>Avahi advertises hostname <code>sovereign</code> and an HTTP service. <code>.local</code> remains an mDNS name rather than a Pi-hole-managed unicast DNS zone.</p><h3 id="first-boot-initializer" tabindex="-1">First-Boot Initializer <a class="header-anchor" href="#first-boot-initializer" aria-label="Permalink to &quot;First-Boot Initializer&quot;">​</a></h3><p>The initializer is a root-owned systemd oneshot unit with explicit dependencies on local filesystems, networking where required, and Docker.</p><p>It must use atomic writes and per-step state or safely detectable outcomes. A final completion marker may be written only after DNS and HTTP smoke tests succeed.</p><h2 id="proposed-port-and-path-ownership" tabindex="-1">Proposed Port and Path Ownership <a class="header-anchor" href="#proposed-port-and-path-ownership" aria-label="Permalink to &quot;Proposed Port and Path Ownership&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Listener</th><th>Owner</th><th>Exposure</th><th>Purpose</th></tr></thead><tbody><tr><td>TCP/UDP 53</td><td>Pi-hole container</td><td>Local network</td><td>DNS</td></tr><tr><td>TCP 80</td><td>Nginx host service</td><td>Local network</td><td>Appliance HTTP entry point</td></tr><tr><td>TCP 8080 or selected high port</td><td>Pi-hole container mapping</td><td>Loopback only</td><td>Proxy backend</td></tr><tr><td><code>/dns/admin/*</code></td><td>Nginx to Pi-hole</td><td>Local network</td><td>Pi-hole UI</td></tr><tr><td><code>/dns/api/*</code></td><td>Nginx to Pi-hole</td><td>Local network</td><td>Pi-hole API</td></tr><tr><td><code>/admin/*</code></td><td>Reserved</td><td>None in Phase 01</td><td>Future Sovereign administration</td></tr><tr><td><code>/api/*</code></td><td>Reserved</td><td>None in Phase 01</td><td>Future Sovereign API</td></tr></tbody></table><h2 id="configuration-and-persistence" tabindex="-1">Configuration and Persistence <a class="header-anchor" href="#configuration-and-persistence" aria-label="Permalink to &quot;Configuration and Persistence&quot;">​</a></h2><p>Proposed host paths:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/etc/sovereign/                  non-secret appliance configuration</span></span>
<span class="line"><span>/data/sovereign/apps/pihole/    persistent Pi-hole state</span></span>
<span class="line"><span>/data/sovereign/secrets/        root-owned secrets</span></span>
<span class="line"><span>/data/sovereign/update-state/   initialization and future update state</span></span>
<span class="line"><span>/var/log/sovereign/             bounded appliance logs</span></span>
<span class="line"><span>/opt/sovereign/bootstrap/       immutable bootstrap assets</span></span></code></pre></div><p><code>/data</code> is a dedicated persistent partition. Pi-hole data must survive restart, container recreation, and future replacement of the root filesystem. Backup and restore semantics will be defined after the initial layout is validated. See <a href="./../adrs/0002-install-images-and-update-artifacts.html">ADR-0002</a>.</p><h2 id="password-delivery" tabindex="-1">Password Delivery <a class="header-anchor" href="#password-delivery" aria-label="Permalink to &quot;Password Delivery&quot;">​</a></h2><p>The device generates a unique Pi-hole administrator password on first boot and passes it using Pi-hole&#39;s supported password-file mechanism.</p><p>For the Phase 01 POC, the device displays that password on the attached physical console after Pi-hole and the local HTTP entry point pass their health checks. The service writes directly to <code>/dev/tty1</code>, not to the system journal. This avoids exposing the secret to unauthenticated LAN clients, the boot partition, or permanent ordinary logs.</p><p>This choice requires temporary physical display access for initial login. A later one-time claim mechanism may replace it without changing the persistent password-file model.</p><p>For headless preview onboarding, <a href="./../adrs/0003-preview-bootstrap-access.html">ADR-0003</a> adds the temporary <code>sovereign</code>/<code>sovereign</code> Linux account. Its password is expired in the shipped image and must be replaced during the first interactive SSH login. Once logged in, the user retrieves the separate, device-unique Pi-hole password from the root-owned secret file. This is an explicit preview exception, not the intended production credential model.</p><h2 id="security-and-privacy" tabindex="-1">Security and Privacy <a class="header-anchor" href="#security-and-privacy" aria-label="Permalink to &quot;Security and Privacy&quot;">​</a></h2><ul><li>No production release may ship a shared password. Phase 01 preview images use the constrained bootstrap exception in ADR-0003.</li><li>No secret in source, image build configuration, Compose YAML, or ordinary logs.</li><li>No Pi-hole web port directly exposed to the LAN.</li><li>No public network binding beyond documented DNS and HTTP ports.</li><li>No Pi-hole DHCP or NTP capabilities by default.</li><li>No privileged container unless a measured requirement is documented.</li><li>Final image scanned for SSH host keys, machine IDs, credentials, and build logs.</li><li>Pinned container digest and published checksums.</li><li>Pi-hole query data remains on the device by default.</li></ul><h2 id="failure-and-recovery" tabindex="-1">Failure and Recovery <a class="header-anchor" href="#failure-and-recovery" aria-label="Permalink to &quot;Failure and Recovery&quot;">​</a></h2><ul><li>Interrupted first boot must resume without destroying valid data.</li><li>Failed container import must preserve the embedded artifact for retry.</li><li>Pi-hole health failure must prevent false completion status.</li><li>Nginx may start only when its configuration validates.</li><li>mDNS failure must not prevent direct-IP use.</li><li>Container recreation must reuse persistent data.</li><li>A recovery procedure must reset first-boot state without silently deleting Pi-hole data.</li></ul><h2 id="updates" tabindex="-1">Updates <a class="header-anchor" href="#updates" aria-label="Permalink to &quot;Updates&quot;">​</a></h2><p>Phase 01 does not implement unattended updates. The initial documented update model is:</p><ol><li>Pin a new Pi-hole digest in a new Sovereign image/release definition.</li><li>Test migration against a copy of persistent data.</li><li>Publish compatibility and rollback notes.</li><li>Perform an explicit update only after backup.</li></ol><p>Users must not run an unbounded <code>latest</code> pull as the supported update process.</p><h2 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to &quot;Testing Strategy&quot;">​</a></h2><ul><li>Static inspection of image contents and identity sanitization</li><li>Boot on real Raspberry Pi 5 hardware</li><li>Offline first boot</li><li>First-boot interruption and restart</li><li>TCP and UDP DNS queries from another device</li><li>UI/API prefix regression tests</li><li>Container recreation and data persistence</li><li>Reboot ordering and recovery</li><li>mDNS client matrix and direct-IP fallback</li><li>Port exposure and firewall inspection</li><li>Final compressed-artifact flash test</li><li>Container digest and release checksum verification</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><h3 id="bare-metal-pi-hole" tabindex="-1">Bare-metal Pi-hole <a class="header-anchor" href="#bare-metal-pi-hole" aria-label="Permalink to &quot;Bare-metal Pi-hole&quot;">​</a></h3><p>Smaller runtime stack but harder to install reproducibly inside a non-running image root and less isolated from the base OS.</p><h3 id="pull-pi-hole-on-first-boot" tabindex="-1">Pull Pi-hole on first boot <a class="header-anchor" href="#pull-pi-hole-on-first-boot" aria-label="Permalink to &quot;Pull Pi-hole on first boot&quot;">​</a></h3><p>Smaller image but creates a mandatory first-boot internet and registry dependency. Rejected for the POC&#39;s appliance promise.</p><h3 id="pi-hole-owns-ports-80-443-directly" tabindex="-1">Pi-hole owns ports 80/443 directly <a class="header-anchor" href="#pi-hole-owns-ports-80-443-directly" aria-label="Permalink to &quot;Pi-hole owns ports 80/443 directly&quot;">​</a></h3><p>Simpler initially but consumes future Sovereign namespaces and prevents central routing. Rejected.</p><h3 id="pi-hole-subdomain" tabindex="-1">Pi-hole subdomain <a class="header-anchor" href="#pi-hole-subdomain" aria-label="Permalink to &quot;Pi-hole subdomain&quot;">​</a></h3><p><code>dns.sovereign.local</code> would be clean after local DNS is operational, but is not as reliable for discovery before clients use Pi-hole. Path namespacing is preferred for Phase 01.</p><h2 id="drawbacks-and-maintenance-cost" tabindex="-1">Drawbacks and Maintenance Cost <a class="header-anchor" href="#drawbacks-and-maintenance-cost" aria-label="Permalink to &quot;Drawbacks and Maintenance Cost&quot;">​</a></h2><ul><li>Docker and Nginx add update and security responsibilities.</li><li>Embedded container artifacts increase image size.</li><li>Three independently versioned layers must be tested: base OS, container runtime, and Pi-hole.</li><li>Prefix routing becomes a release compatibility test.</li><li>Appliance-specific first-boot code must be maintained and recovered safely.</li></ul><h2 id="unresolved-questions" tabindex="-1">Unresolved Questions <a class="header-anchor" href="#unresolved-questions" aria-label="Permalink to &quot;Unresolved Questions&quot;">​</a></h2><ul><li>Completion of the <code>rpi-image-gen</code> proof build and selection of the exact pinned release</li><li>Exact Raspberry Pi OS release</li><li>Requalification of pinned Docker and Pi-hole inputs at release review</li><li>Firewall implementation</li><li>Release stability duration</li><li>Minimum supported storage</li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><p>The proposal is ready for implementation planning when all unresolved questions that affect M2 are decided or explicitly deferred, and the Phase 01 acceptance criteria are testable from the exported image.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>The high-level architecture is accepted in <a href="./../adrs/0001-phase-01-appliance-architecture.html">ADR-0001</a>. This RFC remains Proposed until its unresolved build, credential-delivery, and version choices are reviewed.</p>`,71)])])}const m=i(r,[["render",n]]);export{u as __pageData,m as default};
